#include "incremental/IncrementalLexer.h"
#include <fstream>
#include <iostream>
#include <sstream>
#include <stdexcept>
static std::string readFile(const std::string&p){std::ifstream in(p.c_str(),std::ios::binary);if(!in)throw std::runtime_error("cannot open "+p);std::ostringstream s;s<<in.rdbuf();return s.str();}
int main(int argc,char**argv){if(argc!=3){std::cerr<<"Usage: "<<argv[0]<<" <input.sy> <edit_cases.jsonl>\n";return 1;}try{std::string src=readFile(argv[1]);std::ifstream in(argv[2]);std::ofstream out("results/raw/incremental_results.csv");std::ofstream fail("results/raw/incremental_failures.jsonl");out<<"case_name,file,input_bytes,edit_type,edit_offset,edit_length,rescanned_bytes,full_bytes,reused_tokens,total_old_tokens,reuse_rate,full_lex_us,incremental_lex_us,speedup,equivalent_to_full,reason\n";std::string line;while(std::getline(in,line)){incremental::EditOperation e;if(!incremental::parseEditJsonLine(line,e))continue;incremental::IncrementalLexer lex(src);incremental::IncrementalResult r=lex.apply(e);double reuse=r.totalOldTokenCount?100.0*r.reusedTokenCount/r.totalOldTokenCount:0;double speed=r.incrementalLexUs>0?(double)r.fullLexUs/r.incrementalLexUs:0;out<<e.name<<","<<argv[1]<<","<<r.fullBytes<<","<<incremental::editTypeName(e.type)<<","<<e.offset<<","<<e.length<<","<<r.rescannedBytes<<","<<r.fullBytes<<","<<r.reusedTokenCount<<","<<r.totalOldTokenCount<<","<<reuse<<","<<r.fullLexUs<<","<<r.incrementalLexUs<<","<<speed<<","<<(r.equivalentToFullLex?"true":"false")<<","<<r.reason<<"\n";if(!r.equivalentToFullLex)fail<<line<<"\n";}return 0;}catch(const std::exception&e){std::cerr<<"[incremental_bench] "<<e.what()<<"\n";return 1;}}
